Create BeamDcd.ChunkParser module that wraps :beam_lib.chunks/2 to extract exports and imports from .beam files.

Implementation:
```elixir
defmodule BeamDcd.ChunkParser do
  @type mfa :: {module(), atom(), arity()}

  @spec parse_exports(Path.t()) :: {:ok, [mfa()]} | {:error, term()}
  def parse_exports(beam_file) do
    case :beam_lib.chunks(beam_file, [:exports]) do
      {:ok, {module, [{:exports, exports}]}} ->
        mfas = Enum.map(exports, fn {fun, arity} -> {module, fun, arity} end)
        {:ok, mfas}
      {:error, _} = error -> error
    end
  end

  @spec parse_imports(Path.t()) :: {:ok, [mfa()]} | {:error, term()}
  def parse_imports(beam_file) do
    case :beam_lib.chunks(beam_file, [:imports]) do
      {:ok, {_module, [{:imports, imports}]}} ->
        {:ok, imports}
      {:error, _} = error -> error
    end
  end

  @spec parse_attributes(Path.t()) :: {:ok, keyword()} | {:error, term()}
  def parse_attributes(beam_file) do
    # Extract attributes chunk for behaviour detection
    case :beam_lib.chunks(beam_file, [:attributes]) do
      {:ok, {_module, [{:attributes, attrs}]}} -> {:ok, attrs}
      {:error, _} = error -> error
    end
  end
end
```

Handle edge cases: missing chunks, corrupted BEAM files, stripped debug info. Use pattern matching for robust error handling.

Create BeamDcd.ReferenceCollector that coordinates all three analysis layers.

Implementation:
```elixir
defmodule BeamDcd.ReferenceCollector do
  alias BeamDcd.{ChunkParser, Disassembler, AbstractAnalyzer}

  @type mfa :: {module(), atom(), arity()}
  @type analysis_result :: %{
    used_functions: MapSet.t(mfa()),
    warnings: [String.t()],
    dynamic_dispatch_detected: boolean()
  }

  @spec collect(Path.t()) :: {:ok, analysis_result()} | {:error, term()}
  def collect(beam_file) do
    with {:ok, layer_a} <- ChunkParser.parse_imports(beam_file),
         {:ok, layer_b} <- Disassembler.extract_references(beam_file) do

      # Layer C is optional
      {layer_c, warnings} = case AbstractAnalyzer.extract_references(beam_file) do
        {:ok, refs, warns} -> {refs, warns}
        {:error, :no_debug_info} -> {[], []}
      end

      # Union of all layers
      used = MapSet.new(layer_a ++ layer_b ++ layer_c)

      result = %{
        used_functions: used,
        warnings: warnings,
        dynamic_dispatch_detected: Enum.any?(warnings, &String.contains?(&1, "apply"))
      }

      {:ok, result}
    end
  end

  @spec collect_batch([Path.t()]) :: %{Path.t() => analysis_result()}
  def collect_batch(beam_files) do
    beam_files
    |> Task.async_stream(&{&1, collect(&1)}, timeout: 30_000)
    |> Enum.reduce(%{}, fn {:ok, {path, result}}, acc ->
      case result do
        {:ok, data} -> Map.put(acc, path, data)
        {:error, _} -> acc
      end
    end)
  end
end
```

